sql:
SELECT s.student_id, s.first_name, s.last_name
FROM students s
INNER JOIN course_enrollment ce ON s.student_id = ce.student_id
WHERE ce.course_id = (
    SELECT co.course_id FROM course_offering co WHERE co.offering_id = 1
);

SELECT i.instructor_id, i.first_name, i.last_name
FROM instructors i
WHERE (SELECT COUNT(*) FROM course_offering co WHERE co.instructor_id = i.instructor_id) > 5;

SELECT s.student_id, s.first_name, s.last_name, ap.tuition_fee AS total_tuition_fee
FROM students s
JOIN academic_programs ap ON s.program_id = ap.program_id;

SELECT DISTINCT ce.semester
FROM course_enrollment ce
INNER JOIN course_offering co ON ce.course_id = co.course_id AND ce.semester = co.semester;

SELECT semester, COUNT(course_id) AS course_count
FROM course_offering
GROUP BY semester;

SELECT students.student_id, students.first_name, students.last_name, academic_programs.program_name
FROM students
JOIN academic_programs ON students.program_id = academic_programs.program_id
WHERE students.student_id IN (
    SELECT student_id FROM course_ratings
) AND academic_programs.department_id = 200;
